const input = $input.first().json || {};
const headers = input.headers || {};
const hasWebhookBody = !!input.body || Object.keys(headers).length > 0;

function pad(n) {
  return String(n).padStart(2, '0');
}

function getKstNow() {
  const now = new Date();
  return new Date(now.getTime() + 9 * 60 * 60 * 1000);
}

function getMonthString(date) {
  return date.getFullYear() + '-' + pad(date.getMonth() + 1);
}

function getCurrentCycle(date) {
  return date.getDate() <= 15 ? 'FIRST_HALF' : 'SECOND_HALF';
}

function getScheduledWindow(date) {
  const day = date.getDate();
  if (day === 1) {
    const prevMonth = new Date(Date.UTC(date.getFullYear(), date.getMonth() - 1, 1));
    return {
      month: prevMonth.getUTCFullYear() + '-' + pad(prevMonth.getUTCMonth() + 1),
      cycle: 'SECOND_HALF'
    };
  }
  return {
    month: getMonthString(date),
    cycle: 'FIRST_HALF'
  };
}

if (!hasWebhookBody) {
  const kst = getKstNow();
  const scheduled = getScheduledWindow(kst);
  return [{
    json: {
      _source: 'schedule',
      _action: 'runSettlementBatch',
      month: scheduled.month,
      cycle: scheduled.cycle,
      force: false
    }
  }];
}

const body = input.body || {};
const authHeader = headers.authorization || headers.Authorization || '';
const token = typeof authHeader === 'string' && authHeader.indexOf('Bearer ') === 0 ? authHeader.substring(7).trim() : '';
const expectedToken = $env.ADMIN_API_TOKEN || '';
const isValid = !!token && !!expectedToken && token === expectedToken;

if (!isValid) {
  return [{
    json: {
      _source: 'webhook',
      _action: '_unauthorized'
    }
  }];
}

const kst = getKstNow();
const month = /^\d{4}-\d{2}$/.test(String(body.month || '').trim()) ? String(body.month || '').trim() : getMonthString(kst);
const cycleRaw = String(body.cycle || body.cycle_key || '').trim().toUpperCase();
const cycle = cycleRaw === 'FIRST_HALF' || cycleRaw === 'SECOND_HALF' ? cycleRaw : getCurrentCycle(kst);
const action = String(body.action || 'runSettlementBatch').trim() || 'runSettlementBatch';
const force = body.force === true || String(body.force || '').toLowerCase() === 'true';

return [{
  json: {
    _source: 'webhook',
    _action: action,
    month,
    cycle,
    force
  }
}];

const data = $input.first().json;
const month = /^\d{4}-\d{2}$/.test(String(data.month || '').trim()) ? String(data.month || '').trim() : new Date().toISOString().slice(0, 7);
return [{
  json: {
    ...data,
    month,
    where: '(status,eq,COMPLETED)'
  }
}];

const settlementsResp = $('Get Completed Settlements (History)').first().json;
const partnersResp = $('Get Partners (History)').first().json;
const logsResp = $('Get Settlement Email Logs (History)').first().json;
const params = $('Parse History Params').first().json;

const settlements = settlementsResp.list || [];
const partners = partnersResp.list || [];
const logs = logsResp.list || [];

function cycleInfo(dateStr) {
  const safe = String(dateStr || '').substring(0, 10);
  const day = parseInt(safe.substring(8, 10), 10) || 1;
  const month = safe.substring(0, 7);
  const cycle = day <= 15 ? 'FIRST_HALF' : 'SECOND_HALF';
  const half = cycle === 'FIRST_HALF' ? 'H1' : 'H2';
  return {
    month,
    cycle,
    statementIdPrefix: 'SETB_' + month.replace('-', '') + '_' + half,
    cycleLabel: month + (cycle === 'FIRST_HALF' ? ' 전반' : ' 후반')
  };
}

const partnerMap = {};
for (const partner of partners) {
  partnerMap[partner.partner_code || ''] = {
    partner_name: partner.partner_name || partner.partner_code || '',
    grade: partner.grade || '',
    email: partner.email || ''
  };
}

const logMap = {};
for (const log of logs) {
  const emailType = String(log.email_type || log.type || '').trim();
  const sid = String(log.settlement_id || '').trim();
  if (emailType !== 'SETTLEMENT_STATEMENT' || !sid) continue;
  const sentAt = log.sent_at || log.CreatedAt || '';
  if (!logMap[sid] || sentAt > logMap[sid]) {
    logMap[sid] = sentAt;
  }
}

const grouped = {};
for (const row of settlements) {
  const info = cycleInfo(row.class_date || '');
  if (info.month !== params.month) continue;
  const key = info.statementIdPrefix + '_' + (row.partner_code || '');
  if (!grouped[key]) {
    const partner = partnerMap[row.partner_code || ''] || {};
    grouped[key] = {
      statement_id: key,
      cycle_label: info.cycleLabel,
      partner_code: row.partner_code || '',
      partner_name: partner.partner_name || row.partner_code || '-',
      grade: partner.grade || '',
      recipient_email: partner.email || '',
      classes_count: 0,
      total_order_amount: 0,
      total_commission_amount: 0,
      total_reserve_amount: 0,
      last_sent_at: logMap[key] || ''
    };
  }
  grouped[key].classes_count += 1;
  grouped[key].total_order_amount += Number(row.order_amount) || 0;
  grouped[key].total_commission_amount += Number(row.commission_amount) || 0;
  grouped[key].total_reserve_amount += Number(row.reserve_amount) || 0;
}

const history = Object.values(grouped).sort((a, b) => {
  if (a.cycle_label === b.cycle_label) {
    return (b.total_reserve_amount || 0) - (a.total_reserve_amount || 0);
  }
  return a.cycle_label < b.cycle_label ? 1 : -1;
});

let totalOrderAmount = 0;
let totalReserveAmount = 0;
for (const item of history) {
  totalOrderAmount += item.total_order_amount;
  totalReserveAmount += item.total_reserve_amount;
}

return [{
  json: {
    success: true,
    data: {
      history,
      total: history.length,
      summary: {
        month: params.month,
        total_order_amount: totalOrderAmount,
        total_reserve_amount: totalReserveAmount,
        sent_count: history.filter((item) => !!item.last_sent_at).length
      }
    },
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;
const month = /^\d{4}-\d{2}$/.test(String(data.month || '').trim()) ? String(data.month || '').trim() : new Date().toISOString().slice(0, 7);
const cycle = String(data.cycle || 'FIRST_HALF').toUpperCase() === 'SECOND_HALF' ? 'SECOND_HALF' : 'FIRST_HALF';
const cycleLabel = month + (cycle === 'FIRST_HALF' ? ' 전반' : ' 후반');
return [{
  json: {
    ...data,
    month,
    cycle,
    cycleLabel,
    where: '(status,eq,COMPLETED)'
  }
}];

const settlementsResp = $('Get Completed Settlements (Batch)').first().json;
const partnersResp = $('Get Partners (Batch)').first().json;
const logsResp = $('Get Settlement Email Logs (Batch)').first().json;
const params = $('Parse Batch Params').first().json;

const settlements = settlementsResp.list || [];
const partners = partnersResp.list || [];
const logs = logsResp.list || [];

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatPrice(value) {
  return Number(value || 0).toLocaleString('ko-KR');
}

function getCycleMeta(dateStr) {
  const safe = String(dateStr || '').substring(0, 10);
  const day = parseInt(safe.substring(8, 10), 10) || 1;
  const cycle = day <= 15 ? 'FIRST_HALF' : 'SECOND_HALF';
  const month = safe.substring(0, 7);
  return {
    month,
    cycle,
    half: cycle === 'FIRST_HALF' ? 'H1' : 'H2',
    label: month + (cycle === 'FIRST_HALF' ? ' 전반' : ' 후반')
  };
}

const partnerMap = {};
for (const partner of partners) {
  partnerMap[partner.partner_code || ''] = {
    partner_name: partner.partner_name || partner.partner_code || '',
    grade: partner.grade || '',
    email: String(partner.email || '').trim()
  };
}

const sentIds = {};
for (const log of logs) {
  const emailType = String(log.email_type || log.type || '').trim();
  const sid = String(log.settlement_id || '').trim();
  if (emailType === 'SETTLEMENT_STATEMENT' && sid) {
    sentIds[sid] = true;
  }
}

const grouped = {};
for (const row of settlements) {
  const meta = getCycleMeta(row.class_date || '');
  if (meta.month !== params.month || meta.cycle !== params.cycle) continue;
  const partnerCode = row.partner_code || '';
  if (!partnerCode) continue;
  const statementId = 'SETB_' + params.month.replace('-', '') + '_' + meta.half + '_' + partnerCode;
  if (!grouped[statementId]) {
    const partner = partnerMap[partnerCode] || {};
    grouped[statementId] = {
      statement_id: statementId,
      partner_code: partnerCode,
      partner_name: partner.partner_name || partnerCode,
      recipient_email: partner.email || '',
      grade: partner.grade || '',
      cycle_label: meta.label,
      month: params.month,
      cycle: params.cycle,
      total_order_amount: 0,
      total_commission_amount: 0,
      total_reserve_amount: 0,
      classes_count: 0,
      class_rows: []
    };
  }
  grouped[statementId].classes_count += 1;
  grouped[statementId].total_order_amount += Number(row.order_amount) || 0;
  grouped[statementId].total_commission_amount += Number(row.commission_amount) || 0;
  grouped[statementId].total_reserve_amount += Number(row.reserve_amount) || 0;
  grouped[statementId].class_rows.push({
    class_date: String(row.class_date || '').substring(0, 10),
    class_id: row.class_id || '',
    order_amount: Number(row.order_amount) || 0,
    commission_amount: Number(row.commission_amount) || 0,
    reserve_amount: Number(row.reserve_amount) || 0
  });
}

const statements = [];
for (const key of Object.keys(grouped)) {
  const item = grouped[key];
  if (!item.recipient_email || item.recipient_email.indexOf('@') === -1) continue;
  if (!params.force && sentIds[item.statement_id]) continue;

  let rowsHtml = '';
  for (const row of item.class_rows.slice(0, 10)) {
    rowsHtml += '<tr>'
      + '<td style="padding: 10px 12px; border-bottom: 1px solid #eee;">' + escapeHtml(row.class_date) + '</td>'
      + '<td style="padding: 10px 12px; border-bottom: 1px solid #eee;">' + escapeHtml(row.class_id) + '</td>'
      + '<td style="padding: 10px 12px; border-bottom: 1px solid #eee; text-align: right;">' + formatPrice(row.order_amount) + '원</td>'
      + '<td style="padding: 10px 12px; border-bottom: 1px solid #eee; text-align: right;">' + formatPrice(row.reserve_amount) + '원</td>'
      + '</tr>';
  }

  const html = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /></head><body style="margin:0;padding:0;background:#f7f5f1;font-family:Pretendard,Apple SD Gothic Neo,Malgun Gothic,sans-serif;">'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="padding:24px 0;background:#f7f5f1;"><tr><td align="center">'
    + '<table width="640" cellpadding="0" cellspacing="0" border="0" style="max-width:640px;width:100%;background:#ffffff;border-radius:10px;overflow:hidden;">'
    + '<tr><td style="padding:28px 32px;background:#2f4234;color:#ffffff;">'
    + '<p style="margin:0 0 8px;font-size:12px;letter-spacing:0.12em;opacity:0.72;">SETTLEMENT STATEMENT</p>'
    + '<h1 style="margin:0;font-size:28px;">' + escapeHtml(item.cycle_label) + ' 정산 안내</h1>'
    + '</td></tr>'
    + '<tr><td style="padding:28px 32px;">'
    + '<p style="margin:0 0 12px;font-size:15px;line-height:1.7;color:#333;">' + escapeHtml(item.partner_name) + ' 파트너님,</p>'
    + '<p style="margin:0 0 24px;font-size:14px;line-height:1.8;color:#666;">이번 기간 정산 집계가 완료되었습니다. 아래에서 클래스별 정산 요약과 지급 예정 적립금을 확인하실 수 있습니다.</p>'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:24px;background:#f8f3eb;border:1px solid #ebe3d5;border-radius:8px;">'
    + '<tr><td style="padding:20px 24px;">'
    + '<p style="margin:0 0 8px;font-size:13px;color:#8a6f4d;">지급 예정 적립금</p>'
    + '<p style="margin:0;font-size:28px;font-weight:700;color:#b88956;">' + formatPrice(item.total_reserve_amount) + '원</p>'
    + '<p style="margin:8px 0 0;font-size:12px;color:#777;">총 ' + item.classes_count + '건 집계 · 등급 ' + escapeHtml(item.grade || '-') + '</p>'
    + '</td></tr></table>'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:20px;">'
    + '<tr><td style="padding:10px 12px;background:#faf8f3;font-size:12px;font-weight:700;color:#777;">수강일</td><td style="padding:10px 12px;background:#faf8f3;font-size:12px;font-weight:700;color:#777;">클래스 ID</td><td style="padding:10px 12px;background:#faf8f3;font-size:12px;font-weight:700;color:#777;text-align:right;">주문 금액</td><td style="padding:10px 12px;background:#faf8f3;font-size:12px;font-weight:700;color:#777;text-align:right;">적립금</td></tr>'
    + rowsHtml
    + '</table>'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:20px;">'
    + '<tr><td style="padding:8px 0;font-size:13px;color:#777;">총 주문 금액</td><td style="padding:8px 0;font-size:14px;color:#333;text-align:right;">' + formatPrice(item.total_order_amount) + '원</td></tr>'
    + '<tr><td style="padding:8px 0;font-size:13px;color:#777;">총 수수료</td><td style="padding:8px 0;font-size:14px;color:#333;text-align:right;">' + formatPrice(item.total_commission_amount) + '원</td></tr>'
    + '<tr><td style="padding:8px 0;font-size:13px;color:#777;">총 적립금</td><td style="padding:8px 0;font-size:16px;font-weight:700;color:#b88956;text-align:right;">' + formatPrice(item.total_reserve_amount) + '원</td></tr>'
    + '</table>'
    + '<p style="margin:0;font-size:12px;color:#999;line-height:1.7;">이 안내는 파트너 전용 운영 정산 메일입니다. 세부 문의는 PRESSCO21 운영팀으로 전달해 주세요.</p>'
    + '</td></tr></table></td></tr></table></body></html>';

  statements.push({
    json: {
      _hasTargets: true,
      _source: params._source,
      statement_id: item.statement_id,
      cycle_label: item.cycle_label,
      partner_code: item.partner_code,
      partner_name: item.partner_name,
      recipient_email: item.recipient_email,
      subject: '[PRESSCO21] ' + item.cycle_label + ' 정산 안내',
      html,
      total_order_amount: item.total_order_amount,
      total_commission_amount: item.total_commission_amount,
      total_reserve_amount: item.total_reserve_amount,
      classes_count: item.classes_count,
      month: params.month,
      cycle: params.cycle
    }
  });
}

if (statements.length === 0) {
  return [{
    json: {
      _hasTargets: false,
      _source: params._source,
      success: true,
      data: {
        cycle_label: params.cycleLabel,
        sent_count: 0,
        skipped_count: Object.keys(grouped).length,
        message: '발송할 정산서가 없습니다.'
      },
      _telegramMessage: '[WF-SETTLE] ' + params.cycleLabel + ' 발송 대상 없음'
    }
  }];
}

return statements;

const statementItems = $('Build Statement Payloads').all();
const mailItems = $('Send Settlement Email').all();
let totalOrderAmount = 0;
let totalReserveAmount = 0;
let cycleLabel = '';
let sentCount = 0;
let failedCount = 0;
let firstError = '';

for (const item of statementItems) {
  totalOrderAmount += Number(item.json.total_order_amount) || 0;
  totalReserveAmount += Number(item.json.total_reserve_amount) || 0;
  cycleLabel = item.json.cycle_label || cycleLabel;
}

for (const item of mailItems) {
  const errorValue = item && item.json ? item.json.error : '';
  if (errorValue) {
    failedCount += 1;
    if (!firstError) {
      firstError = typeof errorValue === 'string' ? errorValue : (errorValue.message || JSON.stringify(errorValue));
    }
  } else {
    sentCount += 1;
  }
}

const success = failedCount === 0;
const message = success ? '정산서 발송이 완료되었습니다.' : '정산서 발송 중 실패가 발생했습니다.';

return [{
  json: {
    success,
    data: {
      cycle_label: cycleLabel,
      sent_count: sentCount,
      failed_count: failedCount,
      total_order_amount: totalOrderAmount,
      total_reserve_amount: totalReserveAmount,
      message: message
    },
    error: success ? null : {
      code: 'SETTLEMENT_EMAIL_FAILED',
      message: firstError || 'SMTP 또는 이메일 로그 설정을 확인해 주세요.'
    },
    _telegramMessage: success
      ? '[WF-SETTLE] ' + cycleLabel + ' 정산서 ' + sentCount + '건 발송 완료'
      : '[WF-SETTLE] ' + cycleLabel + ' 정산서 발송 실패 ' + failedCount + '건',
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;
if (data._action === '_unauthorized') {
  return [{
    json: {
      success: false,
      error: {
        code: 'UNAUTHORIZED',
        message: '유효한 Bearer 토큰이 필요합니다.'
      },
      timestamp: new Date().toISOString()
    }
  }];
}
return [{
  json: {
    success: false,
    error: {
      code: 'INVALID_ACTION',
      message: '지원하지 않는 action입니다: ' + (data._action || '')
    },
    timestamp: new Date().toISOString()
  }
}];
